import argparse
import json
import os
import numpy as np
from cogniplan_env import ExplorationEnv
import heapq


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def build_graph(nodes, robot_pos, cur_neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        c = tuple(np.round(np.array(n["coords"], dtype=float), 6))
        coord_to_idx[c] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                c = tuple(np.round(np.array(nb, dtype=float), 6))
                j = coord_to_idx.get(c)
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in cur_neighbors:
        c = tuple(np.round(np.array(nb, dtype=float), 6))
        j = coord_to_idx.get(c)
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class ImprovedPlanner:
    def __init__(self, visited_penalty=0.02, dist_denom=1.0, commit_steps=4):
        self.visited_penalty = visited_penalty
        self.dist_denom = dist_denom
        self.commit_steps = commit_steps
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_nb_idx = None
        self.commit_target_node = None
        self.commit_ttl = 0

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=np.float32)
        neighbors = obs["neighbors"]
        nodes = obs["nodes"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        nb_to_node = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(tuple(np.round(np.array(nb, dtype=float), 6)))
            if j is not None:
                node_to_nb[j] = idx
                nb_to_node[idx] = j

        remaining_steps = 128 - self.step_count

        # --- commitment check ---
        if self.commit_target_node is not None:
            self.commit_ttl -= 1
            tgt = self.commit_target_node
            if 0 <= tgt < N and dist[tgt] < float('inf') and dist[tgt] > 1e-6:
                utility = float(nodes[tgt].get("utility", 0.0))
                if utility > 0 and self.commit_ttl > 0:
                    cur = tgt
                    for _ in range(N + 5):
                        if prev[cur] == r_idx or prev[cur] is None:
                            break
                        cur = prev[cur]
                    if cur in node_to_nb:
                        nb_idx = node_to_nb[cur]
                        self.prev_nb_idx = nb_idx
                        return tuple(float(x) for x in neighbors[nb_idx])
            self.commit_target_node = None
            self.commit_ttl = 0

        # --- score nodes ---
        best_score = -1.0
        best_node = None

        for j in range(N):
            if j == r_idx:
                continue
            d = dist[j]
            if d == float('inf') or d < 1e-6:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue

            score = utility / (d + self.dist_denom)

            if bool(nodes[j].get("visited", False)):
                score *= self.visited_penalty

            if self.prev_nb_idx is not None:
                prev_node = nb_to_node.get(self.prev_nb_idx)
                if prev_node is not None and j == prev_node:
                    score *= 0.05

            est_steps = d / 3.2
            if est_steps > remaining_steps:
                score = -1.0

            if score > best_score:
                best_score = score
                best_node = j

        if best_node is not None and best_score > 0:
            self.commit_target_node = best_node
            self.commit_ttl = self.commit_steps
            cur = best_node
            for _ in range(N + 5):
                if prev[cur] == r_idx or prev[cur] is None:
                    break
                cur = prev[cur]
            if cur in node_to_nb:
                nb_idx = node_to_nb[cur]
                self.prev_nb_idx = nb_idx
                return tuple(float(x) for x in neighbors[nb_idx])

        # --- fallback to nearest frontier ---
        if frontiers:
            best_idx = None
            best_dist = float('inf')
            for idx, nb in enumerate(neighbors):
                nb_arr = np.array(nb, dtype=float)
                for f in frontiers:
                    d = np.linalg.norm(nb_arr - np.array(f, dtype=float))
                    if d < best_dist:
                        best_dist = d
                        best_idx = idx
            if best_idx is not None:
                self.prev_nb_idx = best_idx
                return tuple(float(x) for x in neighbors[best_idx])

        # --- final fallback: move away from previous position ---
        best_idx = 0
        best_dist = -1.0
        for idx, nb in enumerate(neighbors):
            nb_arr = np.array(nb, dtype=float)
            if self.prev_nb_idx is not None:
                prev_pos = np.array(neighbors[self.prev_nb_idx], dtype=float)
                d = np.linalg.norm(nb_arr - prev_pos)
            else:
                d = 0.0
            if d > best_dist:
                best_dist = d
                best_idx = idx
        self.prev_nb_idx = best_idx
        return tuple(float(x) for x in neighbors[best_idx])


def run_episode(env, planner):
    planner.reset()
    obs = env.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        import torch
        _ = torch.load(ckpt_path, map_location="cpu")

    eval_config_path = os.path.join(args.data_path, "eval_config.json")
    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, "r") as f:
            eval_config = json.load(f)
        if isinstance(eval_config, list):
            episodes = eval_config
        elif isinstance(eval_config, dict):
            if "episodes" in eval_config:
                episodes = eval_config["episodes"]

    if not episodes:
        maps_dir = os.path.join(args.data_path, "maps_eval")
        for root, dirs, files in os.walk(maps_dir):
            for fname in files:
                if fname.endswith(".png"):
                    rel = os.path.relpath(os.path.join(root, fname), args.data_path)
                    parts = rel.split(os.sep)
                    env_type = parts[1] if len(parts) > 1 else "unknown"
                    episodes.append({"map_path": rel, "env_type": env_type})

    per_episode = []
    per_type_data = {}

    planner = ImprovedPlanner()

    for ep in episodes:
        map_path = os.path.join(args.data_path, ep["map_path"])
        env_type = ep.get("env_type", "unknown")
        try:
            env = ExplorationEnv(map_path=map_path)
            metrics = run_episode(env, planner)
            success = 1 if metrics.get("success", False) else 0
            distance = float(metrics.get("travel_distance", 0.0))
            explored = float(metrics.get("explored_rate", 0.0))
        except Exception:
            success = 0
            distance = 0.0
            explored = 0.0

        per_episode.append({
            "map_path": ep["map_path"],
            "env_type": env_type,
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })

        if env_type not in per_type_data:
            per_type_data[env_type] = []
        per_type_data[env_type].append({
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })

    total_episodes = len(per_episode)
    success_rate = sum(e["success"] for e in per_episode) / total_episodes if total_episodes else 0.0
    explored_rate = sum(e["explored_rate"] for e in per_episode) / total_episodes if total_episodes else 0.0
    successful_distances = [e["travel_distance"] for e in per_episode if e["success"]]
    travel_distance = sum(successful_distances) / len(successful_distances) if successful_distances else 0.0

    per_type = {}
    for env_type, data in per_type_data.items():
        n = len(data)
        sr = sum(d["success"] for d in data) / n if n else 0.0
        er = sum(d["explored_rate"] for d in data) / n if n else 0.0
        sd = [d["travel_distance"] for d in data if d["success"]]
        td = sum(sd) / len(sd) if sd else 0.0
        per_type[env_type] = {
            "explored_rate": er,
            "travel_distance": td,
            "success_rate": sr
        }

    output = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": total_episodes
    }

    os.makedirs(os.path.dirname(args.output), exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(output, f, indent=2)


if __name__ == "__main__":
    main()
